solution_code:
#include <iostream>
#include <string>

class Rectangle {
public:
    int width;
    int height;
    Rectangle(int w, int h) : width(w), height(h) {}
};

class ColoredRectangle : public Rectangle {
public:
    std::string color;
    ColoredRectangle(int w, int h, std::string c)
        : Rectangle(w, h), color(c)
    {}
    void print() {
        std::cout << "Rectangle: " << width << "x" << height << "\n";
        std::cout << "Color: " << color << "\n";
    }
};

int main() {
    int w, h;
    std::string c;
    std::cin >> w >> h >> c;
    ColoredRectangle cr(w, h, c);
    cr.print();
    return 0;
}

