solution_code:
#include <iostream>
#include <string>

std::string buildLabel(std::string prefix, int value) {
    return prefix + "-" + std::to_string(value);
}

int main() {
    std::string prefix;
    int value;
    std::cin >> prefix >> value;
    std::cout << buildLabel(prefix, value) << "\n";
    return 0;
}
